CompletingBlockingQueue;\n35: import org.apache.flink.core.io.InputStatus;\n36: import org.apache.flink.metrics.Counter;\n37: import org.apache.flink.metrics.groups.OperatorIOMetricGroup;\n38: \n39: import org.slf4j.Logger;\n40: import org.slf4j.LoggerFactory;\n41: \n42: import javax.annotation.Nullable;\n43: \n44: import java.util.ArrayList;\n45: import java.util.Collection;\n46: import java.util.Collections;\n47: import java.util.HashMap;\n48: import java.util.List;\n49: import java.util.Map;\n50: import java.util.Set;\n51: import java.util.concurrent.CompletableFuture;\n52: import java.util.function.Function;\n53: \n54: import static org.apache.flink.util.Preconditions.checkState;\n55: \n56: /**\n57:  * An abstract implementation of {@link SourceReader} which provides some synchronization between\n58:  * the mail box main thread and the SourceReader internal threads. This class allows user to just\n59:  * provide a {@link SplitReader} and snapshot the split state.\n60:  *\n61:  * \u003cp\u003eThis implementation provides the following metrics out of the box:\n62:  *\n63:  * \u003cul\u003e\n64:  *   \u003cli\u003e{@link OperatorIOMetricGroup#getNumRecordsInCounter()}\n65:  * \u003c/ul\u003e\n66:  *\n67:  * @param \u003cE\u003e The rich element type that contains information for split state update or timestamp\n68:  *     extraction.\n69:  * @param \u003cT\u003e The final element type to emit.\n70:  * @param \u003cSplitT\u003e the immutable split type.\n71:  * @param \u003cSplitStateT\u003e the mutable type of split state.\n72:  */\n73: @PublicEvolving\n74: public abstract class SourceReaderBase\u003cE, T, SplitT extends SourceSplit, SplitStateT\u003e\n75:         implements SourceReader\u003cT, SplitT\u003e {\n76:     private static final Logger LOG = LoggerFactory.getLogger(SourceReaderBase.class);\n77: \n78:     /** A queue to buffer the elements fetched by the fetcher thread. */\n79:     private final FutureCompletingBlockingQueue\u003cRecordsWithSplitIds\u003cE\u003e\u003e elementsQueue;\n80: \n81:     /** The state of the splits. */\n82:     private final Map\u003cString, SplitContext\u003cT, SplitStateT\u003e\u003e splitStates;\n83: \n84:     /** The record emitter to handle the records read by the SplitReaders. */\n85:     protected final RecordEmitter\u003cE, T, SplitStateT\u003e recordEmitter;\n86: \n87:     /** The split fetcher manager to run split fetchers. */\n88:     protected final SplitFetcherManager\u003cE, SplitT\u003e splitFetcherManager;\n89: \n90:     /** The configuration for the reader. */\n91:     protected final SourceReaderOptions options;\n92: \n93:     /** The raw configurations that may be used by subclasses. */\n94:     protected final Configuration config;\n95: \n96:     private final Counter numRecordsInCounter;\n97: \n98:     /** The context of this source reader. */\n99:     protected SourceReaderContext context;\n100: \n101:     /** The latest fetched batch of records-by-split from the split reader. */\n102:     @Nullable private RecordsWithSplitIds\u003cE\u003e currentFetch;\n103: \n104:     @Nullable private SplitContext\u003cT, SplitStateT\u003e currentSplitContext;\n105:     @Nullable private SourceOutput\u003cT\u003e currentSplitOutput;\n106: \n107:     /** Indicating whether the SourceReader will be assigned more splits or not. */\n108:     private boolean noMoreSplitsAssignment;\n109: \n110:     @Nullable protected final RecordEvaluator\u003cT\u003e eofRecordEvaluator;\n111: \n112:     /** Indicating whether the SourceReader supports rate limiting or not. */\n113:     private final boolean rateLimitingEnabled;\n114: \n115:     /** The {@link RateLimiter} uses for rate limiting. */\n116:     @Nullable private final RateLimiter\u003cSplitT\u003e rateLimiter;\n117: \n118:     /** Future that tracks the result of acquiring permission from {@link #rateLimiter}. */\n119:     @Nullable private CompletableFuture\u003cVoid\u003e rateLimitPermissionFuture;\n120: \n121: ","url":"https://sourceg